  },
  toolbar: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '6px 10px',
    borderBottom: '1px solid #3c3c3c',
    background: '#252526',
  },
  label: {
    fontWeight: 600,
