import Ajv from 'ajv';
import JSON5 from 'json5';
import type { Diagnostic } from '@codemirror/lint';
import type { EditorView } from '@codemirror/view';
import { sduiScreenSchema, knownTypes, componentPropsSchemas } from './sduiSchema';

const ajv = new Ajv({ allErrors: true, verbose: true, strict: false });
const validate = ajv.compile(sduiScreenSchema);

function didYouMean(input: string, candidates: string[]): string | null {
  let best: string | null = null;
  let bestDist = Infinity;

  for (const candidate of candidates) {
    const dist = levenshtein(input.toLowerCase(), candidate.toLowerCase());
    if (dist < bestDist && dist <= Math.max(2, Math.floor(input.length / 2))) {
      bestDist = dist;
      best = candidate;
    }
  }
  return best;
}

function levenshtein(a: string, b: string): number {
  const m = a.length;
  const n = b.length;
  const dp: number[][] = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));

  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;

  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      dp[i][j] = a[i - 1] === b[j - 1]
        ? dp[i - 1][j - 1]
        : 1 + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
    }
  }
  return dp[m][n];
}

function findJsonPath(doc: string, path: string): { from: number; to: number } | null {
  const segments = path.split('/').filter(Boolean);
  let pos = 0;

  for (const seg of segments) {
    const isIndex = /^\d+$/.test(seg);

    if (isIndex) {
      const idx = parseInt(seg, 10);
      let bracketDepth = 0;
      let currentIdx = -1;
      const arrStart = doc.indexOf('[', pos);
      if (arrStart === -1) return null;
      pos = arrStart + 1;

      while (pos < doc.length && currentIdx < idx) {
        const ch = doc[pos];
        if (ch === '[' || ch === '{') bracketDepth++;
        else if (ch === ']' || ch === '}') bracketDepth--;
        else if (ch === ',' && bracketDepth === 0) currentIdx++;
        else if (bracketDepth === 0 && /[^\s,]/.test(ch) && currentIdx < idx) {
          if (currentIdx === -1) currentIdx = 0;
          if (currentIdx === idx) break;
        }
        if (bracketDepth < 0) break;
        pos++;
      }

      if (currentIdx < idx - 1) {
        const lastBrace = doc.lastIndexOf('{', pos);
        if (lastBrace >= arrStart) pos = lastBrace;
      }
    } else {
      const keyPattern = new RegExp(`"${seg.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}"\\s*:`);
      const match = keyPattern.exec(doc.slice(pos));
      if (!match) return null;
      pos += match.index;
    }
  }

  let lineEnd = doc.indexOf('\n', pos);
  if (lineEnd === -1) lineEnd = doc.length;

  return { from: pos, to: Math.min(pos + 40, lineEnd) };
}

function humanizeMessage(error: Ajv.ErrorObject): string {
  const { keyword, params, instancePath, message } = error;

  if (keyword === 'enum' && instancePath.endsWith('/type')) {
    const value = (error as any).data;
    if (typeof value === 'string') {
      const suggestion = didYouMean(value, [...knownTypes]);
      const base = `Unknown component type "${value}"`;
      return suggestion ? `${base} — did you mean "${suggestion}"?` : `${base}. Valid types: ${knownTypes.join(', ')}`;
    }
  }

  if (keyword === 'required') {
    const missing = (params as any).missingProperty;
    return `Missing required property "${missing}"`;
  }

  if (keyword === 'additionalProperties') {
    const extra = (params as any).additionalProperty;
    return `Unknown property "${extra}"`;
  }

  if (keyword === 'type') {
    const expected = (params as any).type;
    return `Expected ${expected}${message ? ` — ${message}` : ''}`;
  }

  if (keyword === 'const') {
    return `Expected value: ${JSON.stringify((params as any).allowedValue)}`;
  }

  return message || 'Schema validation error';
}

function validateComponentProps(parsed: any, doc: string): Diagnostic[] {
  const diagnostics: Diagnostic[] = [];

  const components: Array<{ component: any; path: string }> = [];

  if (parsed.header) components.push({ component: parsed.header, path: '/header' });
  if (parsed.footer) components.push({ component: parsed.footer, path: '/footer' });
  if (Array.isArray(parsed.body)) {
    parsed.body.forEach((c: any, i: number) => components.push({ component: c, path: `/body/${i}` }));
  }

  for (const { component, path } of components) {
    const type = component?.type;
    if (!type || typeof type !== 'string') continue;

    if (!knownTypes.includes(type as any)) {
      const suggestion = didYouMean(type, [...knownTypes]);
      const loc = findJsonPath(doc, `${path}/type`);
      const msg = suggestion
        ? `Unknown component type "${type}" — did you mean "${suggestion}"?`
        : `Unknown component type "${type}". Valid: ${knownTypes.join(', ')}`;
      diagnostics.push({
        from: loc?.from ?? 0,
        to: loc?.to ?? 0,
        severity: 'warning',
        message: msg,
        source: 'sdui-schema',
      });
      continue;
    }

    const propsSchema = componentPropsSchemas[type] as any;
    if (!propsSchema) continue;

    const required: string[] = propsSchema.required || [];
    const props = component.props || {};
    const knownProps = Object.keys(propsSchema.properties || {});

    for (const req of required) {
      if (props[req] === undefined || props[req] === null) {
        const loc = findJsonPath(doc, `${path}/props`);
        diagnostics.push({
          from: loc?.from ?? 0,
          to: loc?.to ?? 0,
          severity: 'error',
          message: `"${type}" requires property "${req}"`,
          source: 'sdui-schema',
        });
      }
    }

    for (const propName of Object.keys(props)) {
      if (!knownProps.includes(propName)) {
        const suggestion = didYouMean(propName, knownProps);
        const loc = findJsonPath(doc, `${path}/props/${propName}`);
        const msg = suggestion
          ? `Unknown prop "${propName}" on "${type}" — did you mean "${suggestion}"?`
          : `Unknown prop "${propName}" on "${type}". Valid: ${knownProps.join(', ')}`;
        diagnostics.push({
          from: loc?.from ?? 0,
          to: loc?.to ?? 0,
          severity: 'warning',
          message: msg,
          source: 'sdui-schema',
        });
      }
    }
  }

  return diagnostics;
}

export function validateSduiJson(doc: string): Diagnostic[] {
  let parsed: any;

  try {
    parsed = JSON.parse(doc);
  } catch {
    try {
      parsed = JSON5.parse(doc);
    } catch {
      return [];
    }
  }

  if (typeof parsed !== 'object' || parsed === null || Array.isArray(parsed)) {
    return [{
      from: 0,
      to: Math.min(doc.length, 1),
      severity: 'error',
      message: 'SDUI screen must be a JSON object',
      source: 'sdui-schema',
    }];
  }

  const diagnostics: Diagnostic[] = [];

  validate(parsed);
  if (validate.errors) {
    for (const error of validate.errors) {
      if (error.keyword === 'if') continue;

      const jsonPath = error.instancePath || '';
      const loc = findJsonPath(doc, jsonPath);
      const msg = humanizeMessage(error);

      diagnostics.push({
        from: loc?.from ?? 0,
        to: loc?.to ?? 0,
        severity: error.keyword === 'required' || error.keyword === 'type' ? 'error' : 'warning',
        message: msg,
        source: 'sdui-schema',
      });
    }
  }

  diagnostics.push(...validateComponentProps(parsed, doc));

  const seen = new Set<string>();
  return diagnostics.filter(d => {
    const key = `${d.from}:${d.message}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

export function sduiSchemaLinter(view: EditorView): Diagnostic[] {
  return validateSduiJson(view.state.doc.toString());
}

import type { JSONSchemaType } from 'ajv';
import { SDUI_KNOWN_TYPES } from '../../../src/services/sdui/models';

const knownTypes = [...SDUI_KNOWN_TYPES];

const spacingEnum = [
  'none', 'xxxs', 'xxs', 'xs', 'smaller', 'sm', 'md', 'lg', 'xl', 'xxl', 'xxxl',
];

const spacingProp = {
  type: 'string' as const,
  nullable: true as const,
};

const conditionalSchema = {
  type: 'object' as const,
  properties: {
    rule: { type: 'object' as const },
  },
  required: ['rule'] as const,
  additionalProperties: false,
};

const componentPropsSchemas: Record<string, object> = {
  heading: {
    type: 'object',
    properties: {
      text: { type: 'string' },
      color: { type: 'string' },
      mt: spacingProp,
      mb: spacingProp,
      align: { type: 'string' },
      testID: { type: 'string' },
    },
    required: ['text'],
  },
  text: {
    type: 'object',
    properties: {
      text: { type: 'string' },
      type: { type: 'string' },
      color: { type: 'string' },
      colorBold: { type: 'string' },
      mt: spacingProp,
      mb: spacingProp,
      mr: spacingProp,
      ml: spacingProp,
      align: { type: 'string' },
      underline: { type: 'boolean' },
      testID: { type: 'string' },
    },
    required: ['text'],
  },
  section_heading: {
    type: 'object',
    properties: {
      text: { type: 'string' },
      color: { type: 'string' },
      mt: spacingProp,
      mb: spacingProp,
      align: { type: 'string' },
    },
    required: ['text'],
  },
  balance_display: {
    type: 'object',
    properties: {
      label: { type: 'string' },
      pointsFormatted: { type: 'string' },
      priceFormatted: { type: 'string' },
      mt: spacingProp,
      mb: spacingProp,
    },
    required: ['label', 'pointsFormatted', 'priceFormatted'],
  },
  points_input: {
    type: 'object',
    properties: {
      label: { type: 'string' },
      placeholder: { type: 'string' },
      keyboardType: { type: 'string' },
      textRight: { type: 'string' },
      textError: { type: 'string' },
      mb: spacingProp,
      contextKey: { type: 'string' },
    },
    required: ['label'],
  },
  button: {
    type: 'object',
    properties: {
      text: { type: 'string' },
      disabled: { type: 'boolean' },
      mt: spacingProp,
      mb: spacingProp,
      icon: { type: 'string' },
      isLoading: { type: 'boolean' },
      testID: { type: 'string' },
    },
    required: ['text'],
  },
  link: {
    type: 'object',
    properties: {
      text: { type: 'string' },
      color: { type: 'string' },
      mt: spacingProp,
      mb: spacingProp,
      align: { type: 'string' },
    },
    required: ['text'],
  },
  alert: {
    type: 'object',
    properties: {
      label: { type: 'string' },
      type: { type: 'string' },
      icon: { type: 'string' },
      mb: spacingProp,
    },
    required: ['label'],
  },
  list_text_icon: {
    type: 'object',
    properties: {
      items: {
        type: 'array',
        items: {
          type: 'object',
          properties: {
            icon: { type: 'string' },
            iconColor: { type: 'string' },
            iconColorShape: { type: 'string' },
            description: { type: 'string' },
            hasBackgroundIcon: { type: 'boolean' },
          },
          required: ['icon', 'description'],
        },
      },
      type: { type: 'string' },
      ml: spacingProp,
      mr: spacingProp,
      mb: spacingProp,
    },
    required: ['items'],
  },
  separator: {
    type: 'object',
    properties: {
      bgColor: { type: 'string' },
      height: { type: 'number' },
      width: { type: 'string' },
      mt: spacingProp,
      mb: spacingProp,
    },
  },
  icon_text_row: {
    type: 'object',
    properties: {
      icon: { type: 'string' },
      iconColor: { type: 'string' },
      iconSize: { type: 'string' },
      text: { type: 'string' },
      textType: { type: 'string' },
      textColor: { type: 'string' },
      mb: spacingProp,
    },
    required: ['icon', 'text'],
  },
  nav_header: {
    type: 'object',
    properties: {
      title: { type: 'string' },
    },
  },
  rich_text: {
    type: 'object',
    properties: {
      children: {
        type: 'array',
        items: {
          type: 'object',
          oneOf: [
            {
              properties: {
                type: { type: 'string', const: 'text' },
                value: { type: 'string' },
                bold: { type: 'boolean' },
                italic: { type: 'boolean' },
                color: { type: 'string' },
              },
              required: ['type', 'value'],
            },
            {
              properties: {
                type: { type: 'string', const: 'link' },
                text: { type: 'string' },
                to: { type: 'string' },
                trackEvent: { type: 'string' },
              },
              required: ['type', 'text', 'to'],
            },
            {
              properties: {
                type: { type: 'string', const: 'icon' },
                name: { type: 'string' },
                color: { type: 'string' },
                size: { type: 'number' },
              },
              required: ['type', 'name'],
            },
            {
              properties: {
                type: { type: 'string', const: 'br' },
              },
              required: ['type'],
            },
          ],
        },
      },
    },
    required: ['children'],
  },
};

const componentSchemaOneOf = knownTypes.map(type => ({
  if: { properties: { type: { const: type } } },
  then: {
    properties: {
      type: { const: type },
      props: componentPropsSchemas[type] || { type: 'object' as const },
      visible: conditionalSchema,
    },
    required: ['type', 'props'],
  },
}));

export const sduiScreenSchema = {
  $schema: 'http://json-schema.org/draft-07/schema#',
  type: 'object',
  properties: {
    id: { type: 'string' },
    context: { type: 'object' },
    header: {
      type: 'object',
      properties: {
        type: { type: 'string', enum: knownTypes },
        props: { type: 'object' },
        visible: conditionalSchema,
      },
      required: ['type', 'props'],
    },
    body: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          type: { type: 'string' },
          props: { type: 'object' },
          visible: conditionalSchema,
        },
        required: ['type', 'props'],
        allOf: componentSchemaOneOf,
      },
    },
    footer: {
      type: 'object',
      properties: {
        type: { type: 'string', enum: knownTypes },
        props: { type: 'object' },
        visible: conditionalSchema,
      },
      required: ['type', 'props'],
    },
  },
  required: ['id', 'body'],
};

export { knownTypes, componentPropsSchemas };

