import React from 'react';
import type { Preview } from 'storybook/internal/types';
import { ThemeProvider } from '@semparar/design-system-app';
import {
  PhoneFrameDecorator,
  phoneFrameGlobalTypes,
  phoneFrameInitialGlobals,
} from './decorators/PhoneFrameDecorator';

const preview: Preview = {
  decorators: [
    PhoneFrameDecorator,
    Story => (
      <ThemeProvider>
        <Story />
      </ThemeProvider>
    ),
  ],
  globalTypes: {
    ...phoneFrameGlobalTypes,
  },
  initialGlobals: {
    ...phoneFrameInitialGlobals,
  },
  parameters: {
    controls: {
      matchers: {
        color: /(background|color)$/i,
        date: /Date$/i,
      },
    },
  },
};

export default preview;
